19: package org.apache.flink.streaming.api.legacy.io;
20: 
21: import org.apache.flink.annotation.PublicEvolving;
22: import org.apache.flink.api.common.io.FileOutputFormat;
23: import org.apache.flink.core.fs.Path;
24: 
25: import java.io.IOException;
26: import java.io.Serializable;
27: import java.nio.charset.Charset;
28: import java.nio.charset.IllegalCharsetNameException;
29: import java.nio.charset.UnsupportedCharsetException;
30: 
31: /**
32:  * A {@link FileOutputFormat} that writes objects to a text file.
33:  *
34:  * <p>Objects are converted to Strings using either {@link Object#toString()} or a {@link
35:  * TextFormatter}.
36:  *
37:  * @deprecated If you want to read/write data from/to text file, please use FLIP-27 FileSource and
38:  *     Sink-V2 FlinkSink. This class should be removed if we drop all supports for {@link
39:  *     org.apache.flink.api.common.io.InputFormat} and {@link
40:  *     org.apache.flink.api.common.io.OutputFormat}
41:  */
42: @Deprecated
43: @PublicEvolving
44: public class TextOutputFormat<T> extends FileOutputFormat<T> {
45: 
46:     private static final long serialVersionUID = 1L;
47: 
48:     private static final int NEWLINE = '\n';
49: 
50:     private String charsetName;
51: 
52:     // --------------------------------------------------------------------------------------------
53: 
54:     /**
55:      * Formatter that transforms values into their {@link String} representations.
56:      *
57:      * @param <IN> type of input elements
58:      */
59:     @PublicEvolving
60:     public interface TextFormatter<IN> extends Serializable {
61:         String format(IN value);
62:     }
63: 
64:     public TextOutputFormat(Path outputPath) {
65:         this(outputPath, "UTF-8");
66:     }
67: 
68:     public TextOutputFormat(Path outputPath, String charset) {
69:         super(outputPath);
70:         this.charsetName = charset;
71:     }
72: 
73:     public String getCharsetName() {
74:         return charsetName;
75:     }
76: 
77:     public void setCharsetName(String charsetName)
78:             throws IllegalCharsetNameException, UnsupportedCharsetException {
79:         if (charsetName == null) {
80:             throw new NullPointerException();
81:         }
82: 
83:         if (!Charset.isSupported(charsetName)) {
84:             throw new UnsupportedCharsetException(
85:                     "The charset " + charsetName + " is not supported.");
86:         }
87: 
88:         this.charsetName = charsetName;
89:     }
90: 
91:     // --------------------------------------------------------------------------------------------
92: 
93:     @Override
94:     public void writeRecord(T record) throws IOException {
95:         byte[] bytes = record.toString().getBytes(charsetName);
96:         this.stream.write(bytes);
97:         this.stream.write(NEWLINE);
98:     }
99: 
100:     // --------------------------------------------------------------------------------------------
101: 
102:     @Override
103:     public String toString() {
104:         return "TextOutputFormat (" + getOutputFilePath() + ") - " + this.charsetName;
105:     }
106: }
