19: package org.apache.flink.streaming.api.functions.source.datagen;
20: 
21: import org.apache.flink.annotation.Internal;
22: import org.apache.flink.api.common.functions.OpenContext;
23: import org.apache.flink.runtime.state.FunctionInitializationContext;
24: import org.apache.flink.runtime.state.FunctionSnapshotContext;
25: import org.apache.flink.streaming.api.checkpoint.CheckpointedFunction;
26: import org.apache.flink.streaming.api.functions.source.legacy.RichParallelSourceFunction;
27: 
28: import org.slf4j.Logger;
29: import org.slf4j.LoggerFactory;
30: 
31: import javax.annotation.Nullable;
32: 
33: /**
34:  * A data generator source that abstract data generator. It can be used to easy startup/test for
35:  * streaming job and performance testing. It is stateful, re-scalable, possibly in parallel.
36:  *
37:  * @deprecated Use {@code org.apache.flink.connector.datagen.source.DataGeneratorSource} instead.
38:  */
39: @Internal
40: public class DataGeneratorSource<T> extends RichParallelSourceFunction<T>
41:         implements CheckpointedFunction {
42: 
43:     private static final long serialVersionUID = 1L;
44: 
45:     private static final Logger LOG = LoggerFactory.getLogger(DataGeneratorSource.class);
46: 
47:     private final DataGenerator<T> generator;
48: 
49:     private final long rowsPerSecond;
50: 
51:     @Nullable private final Long numberOfRows;
52: 
53:     private transient int outputSoFar;
54: 
55:     private transient int toOutput;
56: 
57:     transient volatile boolean isRunning;
58: 
59:     /**
60:      * Creates a source that emits records by {@link DataGenerator} without controlling emit rate.
61:      *
62:      * @param generator data generator.
63:      */
64:     public DataGeneratorSource(DataGenerator<T> generator) {
65:         this(generator, Long.MAX_VALUE, null);
66:     }
67: 
68:     /**
69:      * Creates a source that emits records by {@link DataGenerator}.
70:      *
71:      * @param generator data generator.
72:      * @param rowsPerSecond Control the emit rate.
73:      * @param numberOfRows Total number of rows to output.
74:      */
75:     public DataGeneratorSource(
76:             DataGenerator<T> generator, long rowsPerSecond, @Nullable Long numberOfRows) {
77:         this.generator = generator;
78:         this.rowsPerSecond = rowsPerSecond;
79:         this.numberOfRows = numberOfRows;
80:     }
81: 
82:     @Override
83:     public void open(OpenContext openContext) throws Exception {
84:         super.open(openContext);
85: 
86:         if (numberOfRows != null) {
87:             final int stepSize = getRuntimeContext().getTaskInfo().getNumberOfParallelSubtasks();
88:             final int taskIdx = getRuntimeContext().getTaskInfo().getIndexOfThisSubtask();
89: 
90:             final int baseSize = (int) (numberOfRows / stepSize);
91:             toOutput = (numberOfRows % stepSize > taskIdx) ? baseSize + 1 : baseSize;
92:         }
93:     }
94: 
95:     @Override
96:     public void initializeState(FunctionInitializationContext context) throws Exception {
97:         this.generator.open("DataGenerator", context, getRuntimeContext());
98:         this.isRunning = true;
99:     }
100: 
101:     @Override
102:     public void snapshotState(FunctionSnapshotContext context) throws Exception {
103:         this.generator.snapshotState(context);
104:     }
105: 
106:     @Override
107:     public void run(SourceContext<T> ctx) throws Exception {
108:         double taskRowsPerSecond =
109:                 (double) rowsPerSecond
110:                         / getRuntimeContext().getTaskInfo().getNumberOfParallelSubtasks();
111:         long nextReadTime = System.currentTimeMillis();
112: 
113:         while (isRunning) {
114:             for (int i = 0; i < taskRowsPerSecond; i++) {
115:                 if (isRunning
116:                         && generator.hasNext()
117:                         && (numberOfRows == null || outputSoFar < toOutput)) {
118:                     synchronized (ctx.getCheckpointLock()) {
119:                         outputSoFar++;
120:                         ctx.collect(this.generator.next());
121:                     }
122:                 } else {
123:                     return;
124:                 }
125:             }
126: 
127:             nextReadTime += 1000;
128:             long toWaitMs = nextReadTime - System.currentTimeMillis();
129:             while (toWaitMs > 0) {
130:                 Thread.sleep(toWaitMs);
131:                 toWaitMs = nextReadTime - System.currentTimeMillis();
132:             }
133:         }
134:     }
135: 
136:     @Override
137:     public void close() throws Exception {
138:         super.close();
139:         LOG.info("generated {} rows", outputSoFar);
140:     }
141: 
142:     @Override
143:     public void cancel() {
144:         isRunning = false;
145:     }
146: }
