364:     @Override
365:     public void initializeState(FunctionInitializationContext context) throws Exception {
366:         // when we are restoring state with pendingCommitTransactions, we don't really know whether
367:         // the
368:         // transactions were already committed, or whether there was a failure between
369:         // completing the checkpoint on the master, and notifying the writer here.
370: 
371:         // (the common case is actually that is was already committed, the window
372:         // between the commit on the master and the notification here is very small)
373: 
374:         // it is possible to not have any transactions at all if there was a failure before
375:         // the first completed checkpoint, or in case of a scale-out event, where some of the
376:         // new task do not have and transactions assigned to check)
377: 
378:         // we can have more than one transaction to check in case of a scale-in event, or
379:         // for the reasons discussed in the 'notifyCheckpointComplete()' method.
380: 
381:         state = context.getOperatorStateStore().getListState(stateDescriptor);
382: 
383:         boolean recoveredUserContext = false;
384:         if (context.isRestored()) {
385:             LOG.info("{} - restoring state", name());
386:             for (State<TXN, CONTEXT> operatorState : state.get()) {
387:                 userContext = operatorState.getContext();
388:                 List<TransactionHolder<TXN>> recoveredTransactions =
389:                         operatorState.getPendingCommitTransactions();
390:                 List<TXN> handledTransactions = new ArrayList<>(recoveredTransactions.size() + 1);
391:                 for (TransactionHolder<TXN> recoveredTransaction : recoveredTransactions) {
392:                     // If this fails to succeed eventually, there is actually data loss
393:                     recoverAndCommitInternal(recoveredTransaction);
394:                     handledTransactions.add(recoveredTransaction.handle);
395:                     LOG.info("{} committed recovered transaction {}", name(), recoveredTransaction);
396:                 }
397: 
398:                 {
399:                     if (operatorState.getPendingTransaction() != null) {
400:                         TXN transaction = operatorState.getPendingTransaction().handle;
401:                         recoverAndAbort(transaction);
402:                         handledTransactions.add(transaction);
403:                         LOG.info(
404:                                 "{} aborted recovered transaction {}",
405:                                 name(),
406:                                 operatorState.getPendingTransaction());
407:                     }
408:                 }
409: 
410:                 if (userContext.isPresent()) {
411:                     finishRecoveringContext(handledTransactions);
412:                     recoveredUserContext = true;
413:                 }
414:             }
415:         }
416: 
417:         // if in restore we didn't get any userContext or we are initializing from scratch
418:         if (!recoveredUserContext) {
419:             LOG.info("{} - no state to restore", name());
420: 
421:             userContext = initializeUserContext();
422:         }
423:         this.pendingCommitTransactions.clear();
424: 
425:         currentTransactionHolder = beginTransactionInternal();
426:         LOG.debug("{} - started new transaction '{}'", name(), currentTransactionHolder);
427:     }
