475:     @Override
476:     public void close() throws Exception {
477:         super.close();
478: 
479:         TXN currentTransaction = currentTransaction();
480:         if (currentTransaction != null) {
481:             abort(currentTransaction);
482:         }
483: 
484:         currentTransactionHolder = null;
