673:     public static final class StateSerializer<TXN, CONTEXT>
674:             extends TypeSerializer<State<TXN, CONTEXT>> {
675: 
676:         private static final long serialVersionUID = 1L;
677: 
678:         private final TypeSerializer<TXN> transactionSerializer;
679:         private final TypeSerializer<CONTEXT> contextSerializer;
680:         private final boolean supportNullPendingTransaction;
681: 
682:         public StateSerializer(
683:                 TypeSerializer<TXN> transactionSerializer,
684:                 TypeSerializer<CONTEXT> contextSerializer) {
685:             this(transactionSerializer, contextSerializer, true);
686:         }
687: 
688:         public StateSerializer(
689:                 TypeSerializer<TXN> transactionSerializer,
690:                 TypeSerializer<CONTEXT> contextSerializer,
691:                 boolean supportNullPendingTransaction) {
692:             this.transactionSerializer = checkNotNull(transactionSerializer);
693:             this.contextSerializer = checkNotNull(contextSerializer);
694:             this.supportNullPendingTransaction = supportNullPendingTransaction;
695:         }
696: 
697:         @Override
698:         public boolean isImmutableType() {
699:             return transactionSerializer.isImmutableType() && contextSerializer.isImmutableType();
700:         }
701: 
702:         @Override
703:         public TypeSerializer<State<TXN, CONTEXT>> duplicate() {
704:             return new StateSerializer<>(
705:                     transactionSerializer.duplicate(),
706:                     contextSerializer.duplicate(),
707:                     supportNullPendingTransaction);
708:         }
709: 
710:         @Override
711:         public State<TXN, CONTEXT> createInstance() {
712:             return null;
713:         }
714: 
715:         @Override
716:         public State<TXN, CONTEXT> copy(State<TXN, CONTEXT> from) {
717:             final TransactionHolder<TXN> pendingTransaction = from.getPendingTransaction();
718:             final TransactionHolder<TXN> copiedPendingTransaction =
719:                     pendingTransaction == null
720:                             ? null
721:                             : new TransactionHolder<>(
722:                                     transactionSerializer.copy(pendingTransaction.handle),
723:                                     pendingTransaction.transactionStartTime);
724: 
725:             final List<TransactionHolder<TXN>> copiedPendingCommitTransactions = new ArrayList<>();
726:             for (TransactionHolder<TXN> txn : from.getPendingCommitTransactions()) {
727:                 final TXN txnHandleCopy = transactionSerializer.copy(txn.handle);
728:                 copiedPendingCommitTransactions.add(
729:                         new TransactionHolder<>(txnHandleCopy, txn.transactionStartTime));
730:             }
731: 
732:             final Optional<CONTEXT> copiedContext = from.getContext().map(contextSerializer::copy);
733:             return new State<>(
734:                     copiedPendingTransaction, copiedPendingCommitTransactions, copiedContext);
735:         }
736: 
737:         @Override
738:         public State<TXN, CONTEXT> copy(State<TXN, CONTEXT> from, State<TXN, CONTEXT> reuse) {
739:             return copy(from);
740:         }
741: 
742:         @Override
743:         public int getLength() {
744:             return -1;
745:         }
746: 
747:         @Override
748:         public void serialize(State<TXN, CONTEXT> record, DataOutputView target)
749:                 throws IOException {
750:             final TransactionHolder<TXN> pendingTransaction = record.getPendingTransaction();
751:             serializePendingTransaction(pendingTransaction, target);
752: 
753:             final List<TransactionHolder<TXN>> pendingCommitTransactions =
754:                     record.getPendingCommitTransactions();
755:             target.writeInt(pendingCommitTransactions.size());
756:             for (TransactionHolder<TXN> pendingTxn : pendingCommitTransactions) {
757:                 transactionSerializer.serialize(pendingTxn.handle, target);
758:                 target.writeLong(pendingTxn.transactionStartTime);
759:             }
760: 
761:             Optional<CONTEXT> context = record.getContext();
762:             if (context.isPresent()) {
763:                 target.writeBoolean(true);
764:                 contextSerializer.serialize(context.get(), target);
765:             } else {
766:                 target.writeBoolean(false);
767:             }
768:         }
769: 
770:         @Override
771:         public State<TXN, CONTEXT> deserialize(DataInputView source) throws IOException {
772:             final TransactionHolder<TXN> pendingTxn = deserializePendingTransaction(source);
773: 
774:             int numPendingCommitTxns = source.readInt();
775:             List<TransactionHolder<TXN>> pendingCommitTxns = new ArrayList<>(numPendingCommitTxns);
776:             for (int i = 0; i < numPendingCommitTxns; i++) {
777:                 final TXN pendingCommitTxnHandle = transactionSerializer.deserialize(source);
778:                 final long pendingCommitTxnStartTime = source.readLong();
779:                 pendingCommitTxns.add(
780:                         new TransactionHolder<>(pendingCommitTxnHandle, pendingCommitTxnStartTime));
781:             }
782: 
783:             Optional<CONTEXT> context = Optional.empty();
784:             boolean hasContext = source.readBoolean();
785:             if (hasContext) {
786:                 context = Optional.of(contextSerializer.deserialize(source));
787:             }
788: 
789:             return new State<>(pendingTxn, pendingCommitTxns, context);
790:         }
791: 
792:         private void serializePendingTransaction(
793:                 @Nullable TransactionHolder<TXN> pendingTransaction, DataOutputView target)
794:                 throws IOException {
795:             if (supportNullPendingTransaction) {
796:                 target.writeBoolean(pendingTransaction != null);
797:             } else {
798:                 checkState(
799:                         pendingTransaction != null,
800:                         "Received null pending transaction while the serializer "
801:                                 + "does not support null pending transaction.");
802:             }
803: 
804:             if (pendingTransaction != null) {
805:                 transactionSerializer.serialize(pendingTransaction.handle, target);
806:                 target.writeLong(pendingTransaction.transactionStartTime);
807:             }
808:         }
809: 
810:         private TransactionHolder<TXN> deserializePendingTransaction(DataInputView source)
811:                 throws IOException {
812:             boolean hasPendingTransaction =
813:                     supportNullPendingTransaction ? source.readBoolean() : true;
814: 
815:             if (!hasPendingTransaction) {
816:                 return null;
817:             }
818: 
819:             TXN pendingTxnHandle = transactionSerializer.deserialize(source);
820:             final long pendingTxnStartTime = source.readLong();
821:             return new TransactionHolder<>(pendingTxnHandle, pendingTxnStartTime);
822:         }
823: 
824:         @Override
825:         public State<TXN, CONTEXT> deserialize(State<TXN, CONTEXT> reuse, DataInputView source)
826:                 throws IOException {
827:             return deserialize(source);
828:         }
829: 
830:         @Override
831:         public void copy(DataInputView source, DataOutputView target) throws IOException {
832:             TransactionHolder<TXN> pendingTransaction = deserializePendingTransaction(source);
833:             serializePendingTransaction(pendingTransaction, target);
834: 
835:             int numPendingCommitTxns = source.readInt();
836:             target.writeInt(numPendingCommitTxns);
837:             for (int i = 0; i < numPendingCommitTxns; i++) {
838:                 TXN pendingCommitTxnHandle = transactionSerializer.deserialize(source);
839:                 transactionSerializer.serialize(pendingCommitTxnHandle, target);
840:                 final long pendingCommitTxnStartTime = source.readLong();
841:                 target.writeLong(pendingCommitTxnStartTime);
842:             }
843: 
844:             boolean hasContext = source.readBoolean();
845:             target.writeBoolean(hasContext);
846:             if (hasContext) {
847:                 CONTEXT context = contextSerializer.deserialize(source);
848:                 contextSerializer.serialize(context, target);
849:             }
850:         }
