36: /** An input format that returns objects from a collection. */
37: public class CollectionInputFormat<T> extends GenericInputFormat<T> implements NonParallelInput {
38: 
39:     private static final long serialVersionUID = 1L;
40:     private static final int MAX_TO_STRING_LEN = 100;
41: 
42:     private TypeSerializer<T> serializer;
43: 
44:     // input data as collection. transient, because it will be serialized in a custom way
45:     private transient Collection<T> dataSet;
46: 
47:     private transient Iterator<T> iterator;
48: 
49:     public CollectionInputFormat(Collection<T> dataSet, TypeSerializer<T> serializer) {
50:         if (dataSet == null) {
51:             throw new NullPointerException();
52:         }
53: 
54:         this.serializer = serializer;
55: 
56:         this.dataSet = dataSet;
57:     }
58: 
59:     @Override
60:     public boolean reachedEnd() throws IOException {
61:         return !this.iterator.hasNext();
62:     }
63: 
64:     @Override
65:     public void open(GenericInputSplit split) throws IOException {
66:         super.open(split);
67: 
68:         this.iterator = this.dataSet.iterator();
69:     }
70: 
71:     @Override
72:     public T nextRecord(T record) throws IOException {
73:         return this.iterator.next();
74:     }
75: 
76:     // --------------------------------------------------------------------------------------------
77: 
78:     private void writeObject(ObjectOutputStream out) throws IOException {
79:         out.defaultWriteObject();
80: 
81:         final int size = dataSet.size();
82:         out.writeInt(size);
83: 
84:         if (size > 0) {
85:             DataOutputViewStreamWrapper wrapper = new DataOutputViewStreamWrapper(out);
86:             for (T element : dataSet) {
87:                 serializer.serialize(element, wrapper);
88:             }
89:         }
90:     }
91: 
92:     private void readObject(ObjectInputStream in) throws IOException, ClassNotFoundException {
93:         in.defaultReadObject();
94: 
95:         int collectionLength = in.readInt();
96:         List<T> list = new ArrayList<T>(collectionLength);
97: 
98:         if (collectionLength > 0) {
99:             try {
100:                 DataInputViewStreamWrapper wrapper = new DataInputViewStreamWrapper(in);
101:                 for (int i = 0; i < collectionLength; i++) {
102:                     T element = serializer.deserialize(wrapper);
103:                     list.add(element);
104:                 }
105:             } catch (Throwable t) {
106:                 throw new IOException("Error while deserializing element from collection", t);
107:             }
108:         }
109: 
110:         dataSet = list;
111:     }
112: 
113:     // --------------------------------------------------------------------------------------------
114: 
115:     @Override
116:     public String toString() {
117:         StringBuilder sb = new StringBuilder();
118:         sb.append('[');
119: 
120:         int num = 0;
121:         for (T e : dataSet) {
122:             sb.append(e);
123:             if (num != dataSet.size() - 1) {
124:                 sb.append(", ");
125:                 if (sb.length() > MAX_TO_STRING_LEN) {
126:                     sb.append("...");
127:                     break;
128:                 }
129:             }
130:             num++;
131:         }
132:         sb.append(']');
133:         return sb.toString();
134:     }
135: 
136:     // --------------------------------------------------------------------------------------------
137: 
138:     public static <X> void checkCollection(Collection<X> elements, Class<X> viewedAs) {
139:         if (elements == null || viewedAs == null) {
140:             throw new NullPointerException();
141:         }
142: 
143:         for (X elem : elements) {
144:             if (elem == null) {
145:                 throw new IllegalArgumentException(
146:                         "The collection must not contain null elements.");
147:             }
148: 
149:             // The second part of the condition is a workaround for the situation that can arise
150:             // from eg.
151:             // "env.fromElements((),(),())"
152:             // In this situation, UnitTypeInfo.getTypeClass returns void.class (when we are in the
153:             // Java world), but
154:             // the actual objects that we will be working with, will be BoxedUnits.
155:             // Note: TypeInformationGenTest.testUnit tests this condition.
156:             if (!viewedAs.isAssignableFrom(elem.getClass())
157:                     && !(elem.getClass().toString().equals("class scala.runtime.BoxedUnit")
158:                             && viewedAs.equals(void.class))) {
159: 
160:                 throw new IllegalArgumentException(
161:                         "The elements in the collection are not all subclasses of "
162:                                 + viewedAs.getCanonicalName());
163:             }
164:         }
165:     }
166: }
